 1	import React, { FC, useState } from 'react';
 2	
 3	import { Button } from '@patternfly/react-core';
 4	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 5	import { CopyToClipboard } from '@utils/components/CopyToClipboard/CopyToClipboard';
 6	import { DetailsItem } from '@utils/components/DetailsItem/DetailsItem';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	import { RouteKind } from '@utils/types';
 9	import MaskedData from '@views/routes/details/components/tabs/detailsTab/components/TLSSettingsSection/MaskedData';
10	
11	type TLSSettingsProps = {
12	  route: RouteKind;
13	};
14	
15	const TLSSettings: FC<TLSSettingsProps> = ({ route }) => {
16	  const { t } = useNetworkingTranslation();
17	  const [showKey, setShowKey] = useState(false);
18	  const { tls } = route.spec;
19	
20	  if (!tls) {
21	    return <>{t('TLS is not enabled')}.</>;
22	  }
23	
24	  const visibleKeyValue = showKey ? tls.key : <MaskedData />;
25	
26	  return (
27	    <dl>
28	      <DetailsItem label={t('Termination type')} obj={route} path="spec.tls.termination" />
29	      <DetailsItem
30	        label={t('Insecure traffic')}
31	        obj={route}
32	        path="spec.tls.insecureEdgeTerminationPolicy"
33	      />
34	      <DetailsItem label={t('Certificate')} obj={route} path="spec.tls.certificate">
35	        {tls?.certificate ? <CopyToClipboard value={tls.certificate} /> : '-'}
36	      </DetailsItem>
37	      <dt className="co-m-route-tls-reveal__title">
38	        {t('Key')}{' '}
39	        {tls?.key && (
40	          <Button
41	            className="pf-m-link--align-left"
42	            onClick={() => setShowKey(!showKey)}
43	            type="button"
44	            variant="link"
45	          >
46	            {showKey ? (
47	              <>
48	                <EyeSlashIcon className="co-icon-space-r" />
49	                {t('Hide')}
50	              </>
51	            ) : (
52	              <>
53	                <EyeIcon className="co-icon-space-r" />
54	                {t('Reveal')}
55	              </>
56	            )}
57	          </Button>
58	        )}
59	      </dt>
60	      <dd>
61	        {tls?.key ? <CopyToClipboard value={tls?.key} visibleValue={visibleKeyValue} /> : '-'}
62	      </dd>
63	      <DetailsItem label={t('CA certificate')} obj={route} path="spec.tls.caCertificate">
64	        {tls.certificate ? <CopyToClipboard value={tls.caCertificate} /> : '-'}
65	      </DetailsItem>
66	      {tls?.termination === 'reencrypt' && (
67	        <DetailsItem
68	          label={t('Destination CA certificate')}
69	          obj={route}
70	          path="spec.tls.destinationCACertificate"
71	        >
72	          {tls?.destinationCACertificate ? (
73	            <CopyToClipboard value={tls.destinationCACertificate} />
74	          ) : (
75	            '-'
76	          )}
77	        </DetailsItem>
78	      )}
79	    </dl>
80	  );
81	};
82	
83	export default TLSSettings;

